+    pub active_remediation_count: usize,
+    /// List of detected problems
+    pub problems: Vec<Problem>,
+    /// Current system metrics
+    pub metrics: SystemMetrics,
+    /// Whether healing is enabled
+    pub enabled: bool,
+    /// Timestamp of last health check
+    pub last_check: u64,
+}
+
+impl HealthStatus {
