+    #[test]
+    fn test_worker_state() {
+        let state = HealingWorkerState::new(HealingWorkerConfig::default());
+
+        assert!(!state.is_running());
+        state.start();
+        assert!(state.is_running());
+        state.stop();
+        assert!(!state.is_running());
+    }
